(function(){"use strict";const s=document.querySelector(".site-header");if(s){const e=()=>s.classList.toggle("is-stuck",window.scrollY>8);e(),window.addEventListener("scroll",e,{passive:!0})}const n=document.querySelector(".nav-toggle"),c=document.body;n&&(n.addEventListener("click",()=>{const e=c.classList.toggle("nav-open");n.setAttribute("aria-expanded",String(e))}),document.querySelectorAll(".nav-links a").forEach(e=>e.addEventListener("click",()=>{c.classList.remove("nav-open"),n.setAttribute("aria-expanded","false")})));const a=document.querySelectorAll(".reveal");if("IntersectionObserver"in window&&a.length){const e=new IntersectionObserver(o=>{o.forEach(t=>{t.isIntersecting&&(t.target.classList.add("in"),e.unobserve(t.target))})},{threshold:.12,rootMargin:"0px 0px -40px 0px"});a.forEach(o=>e.observe(o))}else a.forEach(e=>e.classList.add("in"));const r=document.querySelectorAll("[data-menu-tab]"),d=document.querySelectorAll("[data-menu-panel]");r.length&&r.forEach(e=>{e.addEventListener("click",()=>{const o=e.getAttribute("data-menu-tab");r.forEach(t=>t.setAttribute("aria-selected",String(t===e))),d.forEach(t=>{t.hidden=t.getAttribute("data-menu-panel")!==o})})});const l=document.querySelectorAll("[data-day]");if(l.length){const e=new Date().getDay();l.forEach(o=>{Number(o.getAttribute("data-day"))===e&&o.classList.add("today")})}document.querySelectorAll("[data-demo-form]").forEach(e=>{e.addEventListener("submit",o=>{o.preventDefault();const t=e.querySelector(".form-success");t&&(t.classList.add("show"),t.scrollIntoView({behavior:"smooth",block:"center"})),e.reset()})}),document.querySelectorAll("[data-year]").forEach(e=>{e.textContent=new Date().getFullYear()})})();
